type LegacyRequest = {
  method: string;
  url: string;
  headers: Record<string, string>;
  body?: unknown;
  query: Record<string, string>;
};

type LegacyResponse = {
  setHeader(name: string, value: string): void;
  status(code: number): LegacyResponse;
  json(value: unknown): Response;
  send(value: unknown): Response;
  end(value?: unknown): Response;
};

type LegacyHandler = (
  req: LegacyRequest,
  res: LegacyResponse
) => Response | Promise<Response | void> | void;

function headersObject(headers: Headers) {
  const out: Record<string, string> = {};
  headers.forEach((value, key) => {
    out[key] = value;
    out[key.toLowerCase()] = value;
  });
  return out;
}

function queryObject(url: URL, extra: Record<string, string>) {
  const out: Record<string, string> = {};
  url.searchParams.forEach((value, key) => {
    out[key] = value;
  });
  return { ...out, ...extra };
}

async function parseBody(request: Request) {
  if (request.method === "GET" || request.method === "HEAD") return undefined;

  const text = await request.text();
  if (!text) return undefined;

  const contentType = request.headers.get("content-type") || "";
  if (contentType.includes("application/json")) {
    return JSON.parse(text);
  }
  return text;
}

export async function runLegacyHandler(
  handler: LegacyHandler,
  request: Request,
  extraQuery: Record<string, string> = {}
) {
  const url = new URL(request.url);
  const responseHeaders = new Headers();
  let statusCode = 200;
  let resolved: Response | null = null;

  const finish = (body?: unknown) => {
    if (resolved) return resolved;

    if (body instanceof Response) {
      resolved = body;
      return resolved;
    }

    let payload: BodyInit | null = null;
    if (body !== undefined && body !== null) {
      payload = typeof body === "string" ? body : JSON.stringify(body);
    }

    resolved = new Response(payload, {
      status: statusCode,
      headers: responseHeaders
    });
    return resolved;
  };

  const req: LegacyRequest = {
    method: request.method,
    url: `${url.pathname}${url.search}`,
    headers: headersObject(request.headers),
    body: await parseBody(request),
    query: queryObject(url, extraQuery)
  };

  const res: LegacyResponse = {
    setHeader(name, value) {
      responseHeaders.set(name, value);
    },
    status(code) {
      statusCode = code;
      return res;
    },
    json(value) {
      if (!responseHeaders.has("Content-Type")) {
        responseHeaders.set("Content-Type", "application/json; charset=utf-8");
      }
      return finish(JSON.stringify(value));
    },
    send(value) {
      return finish(value);
    },
    end(value) {
      return finish(value);
    }
  };

  const result = await handler(req, res);
  return finish(result);
}
